import React, { useState, useRef, useEffect } from 'react';

function TestImg( {itemData} ) {
  const [isFixed, setIsFixed] = useState(false);
  const imagesRef = useRef(null);
  const infoRef = useRef(null);

  useEffect(() => {
    const handleScroll = () => {
      const imagesContainer = imagesRef.current;
      const infoContainer = infoRef.current;

      if (!imagesContainer || !infoContainer) return;

      const imagesContainerBottom = imagesContainer.getBoundingClientRect().bottom;
      const scrollTop = window.pageYOffset || document.documentElement.scrollTop;

      setIsFixed(scrollTop >= imagesContainerBottom);
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  console.log(itemData)
  return (
    <div className="flex gap-2 mt-10 w-full">
      {/* Left div with images */}
      <div className="w-1/2" ref={imagesRef}>
        {itemData?.photos?.map((pic, index) => (
          <div className="flex gap-2" key={index}>
            <img
              className="rounded-2xl object-cover"
              alt="img not found"
              src={"http://localhost:5000/" + pic}
            />
          </div>
        ))}
      </div>

      {/* Right div with information */}
      <div className={`w-1/2 ${isFixed ? 'fixed top-0' : ''}`} ref={infoRef}>
        {/* Content for the right div (information) */}
        <h1>{itemData?.iname}</h1>
        {/* Add more content as needed */}
      </div>
    </div>
  );
}

export default TestImg;
